#include<bits/stdc++.h>
using namespace std;
string a;
int l=0,r=0,a1,a2,a3,flag=0,flag2=1;
int main(){
    cin>>a;

    for(int r=0;r<=a.size();r++){
        if(a[r]==','||r==a.size()){
            if(r-l>=6&&r-l<=12&&(a1+a2+a3)>=2&&flag&&flag2){
                for(int i=l;i<=r-1;i++){
                    cout<<a[i];
                }
                cout<<'\n';
            }
            l=r+1;
            a1=0;
            a2=0;
            a3=0;
            flag=0;
            flag2=1;
        }else{
            if((a[r]>='a'&&a[r]<='z')||(a[r]>='A'&&a[r]<='Z')||(a[r]>='0'&&a[r]<='9')||a[r]=='!'||a[r]=='@'||a[r]=='#'||a[r]=='$'){
                if(a[r]>='a'&&a[r]<='z'){
                    a1=1;
                }else if(a[r]>='A'&&a[r]<='Z'){
                    a2=1;
                }else if(a[r]>='0'&&a[r]<='9'){
                    a3=1;
                }else{
                    flag=1;
                }
            }else{
                flag2=0;
            }
        }
    }
    return 0;
}
